const express = require('express');
const app = express();

// ---------------------------------------------------------------------------
// 1. Security headers — mitigate XSS, clickjacking, MIME-sniffing, etc.
//    In production, prefer the `helmet` package for a more comprehensive set.
// ---------------------------------------------------------------------------
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '0');                    // modern best-practice: rely on CSP instead
  res.setHeader('Strict-Transport-Security', 'max-age=63072000; includeSubDomains');
  res.setHeader('Content-Security-Policy', "default-src 'none'");
  next();
});

// ---------------------------------------------------------------------------
// 2. Body parsing with size limits to prevent large-payload DoS
// ---------------------------------------------------------------------------
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: false, limit: '1mb' }));

// ---------------------------------------------------------------------------
// 3. Simple in-memory rate limiter (per-IP, resets every window)
//    In production, use `express-rate-limit` with a Redis/Memcached store.
// ---------------------------------------------------------------------------
const RATE_LIMIT_WINDOW_MS = 15 * 60 * 1000; // 15 minutes
const RATE_LIMIT_MAX = 100;                    // max requests per window
const rateLimitMap = new Map();

app.use((req, res, next) => {
  const ip = req.ip;
  const now = Date.now();
  const entry = rateLimitMap.get(ip) || { count: 0, start: now };

  if (now - entry.start > RATE_LIMIT_WINDOW_MS) {
    entry.count = 0;
    entry.start = now;
  }

  entry.count += 1;
  rateLimitMap.set(ip, entry);

  if (entry.count > RATE_LIMIT_MAX) {
    return res.status(429).json({ error: 'Too many requests. Please try again later.' });
  }
  next();
});

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const allowedParams = ['page', 'limit'];
  const unknownParams = Object.keys(req.query).filter((p) => !allowedParams.includes(p));
  if (unknownParams.length > 0) {
    return res.status(400).json({
      error: 'Unknown query parameters',
      unknownParams,
    });
  }

  const page = Math.max(1, parseInt(req.query.page, 10) || 1);
  const limit = Math.min(100, Math.max(1, parseInt(req.query.limit, 10) || 10));

  // Static data for now — pagination values are validated & ready for a real store
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json({ page, limit, data: users });
});

// ---------------------------------------------------------------------------
// 4. 404 handler — explicitly catch unmatched routes
// ---------------------------------------------------------------------------
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ---------------------------------------------------------------------------
// 5. Global error handler — never leak stack traces to clients
// ---------------------------------------------------------------------------
app.use((err, req, res, _next) => {
  console.error('Unhandled error:', err);
  res.status(err.status || 500).json({
    error: 'Internal server error',
    // Only include details in non-production environments
    ...(process.env.NODE_ENV !== 'production' && { message: err.message }),
  });
});

// ---------------------------------------------------------------------------
// 6. Configurable port via environment variable
// ---------------------------------------------------------------------------
const PORT = parseInt(process.env.PORT, 10) || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

